        od = abs(rx - ox) + abs(ry - oy)
        adv = od - sd
        if adv > best_adv:
            best_adv = adv
            best_res = (rx, ry)
        elif adv == best_adv and best_res is not None:
            brx, bry = best_res
            bsd = abs(brx - sx) + abs(bry - sy)
            if sd < bsd or (sd == bsd and (rx, ry) < (brx, bry)):
                best_res = (rx, ry)

